class TreeNode:
    def __init__(self, val):
        self.val = val
        self.left = None
        self.right = None

# Preorder: Root -> Left -> Right
def preorder(node):
    if node:
        print(node.val, end=' ')  # Visit root
        preorder(node.left)       # Traverse left
        preorder(node.right)      # Traverse right

# Inorder: Left -> Root -> Right
def inorder(node):
    if node:
        inorder(node.left)        # Traverse left
        print(node.val, end=' ')  # Visit root
        inorder(node.right)       # Traverse right

# Postorder: Left -> Right -> Root
def postorder(node):
    if node:
        postorder(node.left)      # Traverse left
        postorder(node.right)     # Traverse right
        print(node.val, end=' ')  # Visit root

from collections import deque

def level_order(root):
    if not root:
        return []

    queue = deque([root])
    result = []

    while queue:
        node = queue.popleft()  # Dequeue front
        result.append(node.val)  # Visit node

        # Enqueue left child
        if node.left:
            queue.append(node.left)

        # Enqueue right child
        if node.right:
            queue.append(node.right)

    return result
